1	import test from "node:test";
2	import assert from "node:assert/strict";
3	import { existsSync, mkdtempSync, mkdirSync, readFileSync, rmSync, writeFileSync } from "node:fs";
4	import { dirname, join } from "node:path";
5	import { tmpdir } from "node:os";
6	import { fileURLToPath } from "node:url";
7	import { Client } from "@modelcontextprotocol/sdk/client/index.js";
8	import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";
9	
10	import {
11	  buildWorkflowMcpServers,
12	  detectWorkflowMcpLaunchConfig,
13	  getWorkflowTransportSupportError,
14	  getRequiredWorkflowToolsForAutoUnit,
15	  getRequiredWorkflowToolsForGuidedUnit,
16	  usesWorkflowMcpTransport,
17	} from "../workflow-mcp.ts";
18	
19	const __dirname = dirname(fileURLToPath(import.meta.url));
20	const gsdDir = join(__dirname, "..");
21	
22	function readSrc(file: string): string {
23	  return readFileSync(join(gsdDir, file), "utf-8");
24	}
25	
26	test("guided execute-task requires canonical task completion tool", () => {
27	  assert.deepEqual(getRequiredWorkflowToolsForGuidedUnit("execute-task"), ["gsd_task_complete"]);
28	});
29	
30	test("auto execute-task requires legacy completion alias until prompt contract is aligned", () => {
31	  assert.deepEqual(getRequiredWorkflowToolsForAutoUnit("execute-task"), ["gsd_complete_task"]);
32	});
33	
34	test("detectWorkflowMcpLaunchConfig prefers explicit env override", () => {
35	  const launch = detectWorkflowMcpLaunchConfig("/tmp/project", {
36	    GSD_WORKFLOW_MCP_NAME: "workflow-tools",
37	    GSD_WORKFLOW_MCP_COMMAND: "node",
38	    GSD_WORKFLOW_MCP_ARGS: JSON.stringify(["dist/cli.js"]),
39	    GSD_WORKFLOW_MCP_ENV: JSON.stringify({ FOO: "bar" }),
40	    GSD_WORKFLOW_MCP_CWD: "/tmp/project",
41	    GSD_CLI_PATH: "/tmp/gsd",
42	  });
43	
44	  assert.deepEqual(launch, {
45	    name: "workflow-tools",
46	    command: "node",
47	    args: ["dist/cli.js"],
48	    cwd: "/tmp/project",
49	    env: launch?.env,
50	  });
51	  assert.equal(launch?.env?.FOO, "bar");
52	  assert.equal(launch?.env?.GSD_CLI_PATH, "/tmp/gsd");
53	  assert.equal(launch?.env?.GSD_PERSIST_WRITE_GATE_STATE, "1");
54	  assert.equal(launch?.env?.GSD_WORKFLOW_PROJECT_ROOT, "/tmp/project");
55	  assert.match(launch?.env?.GSD_WORKFLOW_EXECUTORS_MODULE ?? "", /workflow-tool-executors\.(js|ts)$/);
56	  assert.match(launch?.env?.GSD_WORKFLOW_WRITE_GATE_MODULE ?? "", /write-gate\.(js|ts)$/);
57	});
58	
59	test("buildWorkflowMcpServers mirrors explicit launch config", () => {
60	  const servers = buildWorkflowMcpServers("/tmp/project", {
61	    GSD_WORKFLOW_MCP_COMMAND: "node",
62	    GSD_WORKFLOW_MCP_ARGS: JSON.stringify(["dist/cli.js"]),
63	  });
64	
65	  assert.deepEqual(servers, {
66	    "gsd-workflow": {
67	      command: "node",
68	      args: ["dist/cli.js"],
69	      env: servers?.["gsd-workflow"]?.env,
70	    },
71	  });
72	  assert.equal((servers?.["gsd-workflow"]?.env as Record<string, string> | undefined)?.GSD_PERSIST_WRITE_GATE_STATE, "1");
73	  assert.equal((servers?.["gsd-workflow"]?.env as Record<string, string> | undefined)?.GSD_WORKFLOW_PROJECT_ROOT, "/tmp/project");
74	  assert.match((servers?.["gsd-workflow"]?.env as Record<string, string> | undefined)?.GSD_WORKFLOW_EXECUTORS_MODULE ?? "", /workflow-tool-executors\.(js|ts)$/);
75	  assert.match((servers?.["gsd-workflow"]?.env as Record<string, string> | undefined)?.GSD_WORKFLOW_WRITE_GATE_MODULE ?? "", /write-gate\.(js|ts)$/);
76	});
77	
78	test("detectWorkflowMcpLaunchConfig resolves the bundled server from GSD_PROJECT_ROOT", () => {
79	  const repoRoot = mkdtempSync(join(tmpdir(), "gsd-workflow-root-"));
80	  const worktreeRoot = mkdtempSync(join(tmpdir(), "gsd-workflow-worktree-"));
81	  const cliPath = join(repoRoot, "packages", "mcp-server", "dist", "cli.js");
82	
83	  mkdirSync(join(repoRoot, "packages", "mcp-server", "dist"), { recursive: true });
84	  writeFileSync(cliPath, "#!/usr/bin/env node\n", "utf-8");
