320	async function main() {
321	    const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 3000;
322	    const app = createMcpExpressApp();
323	    // Map to store transports by session ID
324	    const transports = {};
325	    // MCP POST endpoint
326	    const mcpPostHandler = async (req, res) => {
327	        const sessionId = req.headers['mcp-session-id'];
328	        if (sessionId) {
329	            console.log(`Received MCP request for session: ${sessionId}`);
330	        }
331	        try {
332	            let transport;
333	            if (sessionId && transports[sessionId]) {
334	                // Reuse existing transport for this session
335	                transport = transports[sessionId];
336	            }
337	            else if (!sessionId && isInitializeRequest(req.body)) {
338	                // New initialization request - create new transport
339	                transport = new StreamableHTTPServerTransport({
340	                    sessionIdGenerator: () => randomUUID(),
341	                    onsessioninitialized: sessionId => {
342	                        // Store the transport by session ID when session is initialized
343	                        console.log(`Session initialized with ID: ${sessionId}`);
344	                        transports[sessionId] = transport;
345	                    }
346	                });
347	                // Set up onclose handler to clean up transport when closed
348	                transport.onclose = () => {
349	                    const sid = transport.sessionId;
350	                    if (sid && transports[sid]) {
351	                        console.log(`Transport closed for session ${sid}, removing from transports map`);
352	                        delete transports[sid];
353	                    }
354	                };
355	                // Create a new server per session and connect it to the transport
356	                const mcpServer = getServer();
357	                await mcpServer.connect(transport);
358	                await transport.handleRequest(req, res, req.body);
359	                return;
360	            }
361	            else {
362	                // Invalid request - no session ID or not initialization request
363	                res.status(400).json({
364	                    jsonrpc: '2.0',
365	                    error: {
366	                        code: -32000,
367	                        message: 'Bad Request: No valid session ID provided'
