const OTHER_OPTION_LABEL = "None of the above";

function formatAskUserQuestionsResult(result: RoundResult): string {
  const answers: Record<string, { answers: string[] }> = {};
  for (const [id, answer] of Object.entries(result.answers)) {
    const list = Array.isArray(answer.selected) ? [...answer.selected] : [answer.selected];
    if (answer.notes) {
      list.push(`user_note: ${answer.notes}`);
    }
    answers[id] = { answers: list };
  }
  return JSON.stringify({ answers });
}

function errorAskUserQuestionsResult(message: string, questions: Question[] = []): { content: { type: "text"; text: string }[]; details: unknown } {
  return {
    content: [{ type: "text", text: message }],
    details: { questions, response: null, cancelled: true },
  };
}

function buildQuestionSchemaProperty(question: Question): ElicitFormSchemaProperty {
  const optionLabels = question.options.map((option) => option.label);
  if (question.allowMultiple) {
    return {
      type: "array",
      title: question.header,
      description: question.question,
      minItems: 1,
      maxItems: optionLabels.length,
      items: { type: "string", enum: optionLabels },
      default: optionLabels[0] ? [optionLabels[0]] : undefined,
    };
  }

  const labels = [...optionLabels, OTHER_OPTION_LABEL];
  return {
    type: "string",
    title: question.header,
    description: question.question,
    enum: labels,
    enumNames: labels,
    default: optionLabels[0],
  };
}

function buildAskUserQuestionsSchema(questions: Question[]) {
  const properties: Record<string, ElicitFormSchemaProperty> = {};
  for (const question of questions) {
    properties[question.id] = buildQuestionSchemaProperty(question);
  }
  return {
    type: "object" as const,
    properties,
    required: questions.map((question) => question.id),
  };
}

function formContentToRoundResult(questions: Question[], content: Record<string, string | number | boolean | string[]>): RoundResult {
  const answers: RoundResult["answers"] = {};
  for (const question of questions) {
    const raw = content[question.id];
    if (raw === undefined) continue;
    if (question.allowMultiple) {
      answers[question.id] = {
        selected: Array.isArray(raw) ? raw.map(String) : [String(raw)],
        notes: "",
      };
      continue;
    }
    answers[question.id] = {
      selected: Array.isArray(raw) ? String(raw[0] ?? "") : String(raw),
      notes: "",
    };
  }
  return { endInterview: false, answers };
}

function parseAskUserQuestionsArgs(args: Record<string, unknown>): { questions: Question[] } {
  return parseToolArgs(askUserQuestionsSchema, args);
}

async function handleAskUserQuestions(server: McpToolServer, args: Record<string, unknown>): Promise<unknown> {
  const { questions } = parseAskUserQuestionsArgs(args);
  if (questions.length === 0 || questions.length > 3) {
    return errorAskUserQuestionsResult("Error: questions must contain 1-3 items", questions);
  }
  for (const question of questions) {
    if (!question.options || question.options.length === 0) {
      return errorAskUserQuestionsResult(
        `Error: ask_user_questions requires non-empty options for every question (question "${question.id}" has none)`,
        questions,
      );
    }
  }

  const elicitInput = server.server?.elicitInput;
  if (!elicitInput) {
    return errorAskUserQuestionsResult("Error: MCP client does not expose form elicitation", questions);
  }

  const result = await elicitInput({
    mode: "form",
    message: questions.map((question) => `${question.header}: ${question.question}`).join("\n"),
    requestedSchema: buildAskUserQuestionsSchema(questions),
  });

  if (result.action !== "accept" || !result.content) {
    return errorAskUserQuestionsResult("ask_user_questions was cancelled before receiving a response", questions);
  }

  const roundResult = formContentToRoundResult(questions, result.content);
  return {
    content: [{ type: "text" as const, text: formatAskUserQuestionsResult(roundResult) }],
    details: { questions, response: roundResult, cancelled: false },
  };
}

