type QuestionOption = {
  label: string;
  description: string;
};

type Question = {
  id: string;
  header: string;
  question: string;
  options: QuestionOption[];
  allowMultiple?: boolean;
};

type RoundResult = {
  endInterview: boolean;
  answers: Record<string, { selected: string | string[]; notes?: string }>;
};

type ElicitFormResult = {
  action: "accept" | "decline" | "cancel";
  content?: Record<string, string | number | boolean | string[]>;
};

type ElicitFormSchemaProperty =
  | {
      type: "string";
      title?: string;
      description?: string;
      enum: string[];
      enumNames?: string[];
      default?: string;
    }
  | {
      type: "array";
      title?: string;
      description?: string;
      minItems?: number;
      maxItems?: number;
      items: { type: "string"; enum: string[] };
      default?: string[];
    };

type ElicitInput = (params: {
  mode: "form";
  message: string;
  requestedSchema: {
    type: "object";
    properties: Record<string, ElicitFormSchemaProperty>;
    required?: string[];
  };
}) => Promise<ElicitFormResult>;

type WorkflowWriteGateModule = {
  loadWriteGateSnapshot: (basePath?: string) => {
    verifiedDepthMilestones: string[];
    activeQueuePhase: boolean;
    pendingGateId: string | null;
  };
  shouldBlockPendingGateInSnapshot: (
    snapshot: {
      verifiedDepthMilestones: string[];
      activeQueuePhase: boolean;
      pendingGateId: string | null;
    },
    toolName: string,
    milestoneId: string | null,
    queuePhaseActive?: boolean,
  ) => { block: boolean; reason?: string };
  shouldBlockQueueExecutionInSnapshot: (
    snapshot: {
      verifiedDepthMilestones: string[];
      activeQueuePhase: boolean;
      pendingGateId: string | null;
    },
    toolName: string,
