      env: buildWorkflowLaunchEnv(resolvedWorkflowProjectRoot, gsdCliPath),
    };
  }

  const distCli = resolve(resolvedWorkflowProjectRoot, "packages", "mcp-server", "dist", "cli.js");
  if (existsSync(distCli)) {
    return {
      name,
      command: process.execPath,
      args: [distCli],
