function findWorkflowCliFromAncestorPath(startPath: string, env: NodeJS.ProcessEnv = process.env): string | null {
  let current = resolve(startPath);

  while (true) {
    const sourceCandidate = resolve(current, "packages", "mcp-server", "src", "cli.ts");
    if (hasTsResolveHook(env) && existsSync(sourceCandidate)) return sourceCandidate;

    const candidate = resolve(current, "packages", "mcp-server", "dist", "cli.js");
    if (existsSync(candidate)) return candidate;

    const parent = dirname(current);
    if (parent === current) break;
    current = parent;
  }

  return null;
}

function getBundledWorkflowMcpCliPath(env: NodeJS.ProcessEnv): string | null {
  const envAnchors = [
    env.GSD_BIN_PATH?.trim(),
    env.GSD_CLI_PATH?.trim(),
    env.GSD_WORKFLOW_PATH?.trim(),
  ].filter((value): value is string => typeof value === "string" && value.length > 0);

  for (const anchor of envAnchors) {
    const candidate = findWorkflowCliFromAncestorPath(anchor, env);
    if (candidate) return candidate;
  }

  const candidates = [
    resolve(fileURLToPath(new URL("../../../../packages/mcp-server/dist/cli.js", import.meta.url))),
    resolve(fileURLToPath(new URL("../../../../../packages/mcp-server/dist/cli.js", import.meta.url))),
  ];

  for (const bundledCli of candidates) {
    if (existsSync(bundledCli)) return bundledCli;
  }

  return null;
}

function getBundledWorkflowExecutorModulePath(env: NodeJS.ProcessEnv = process.env): string | null {
  const sourceCandidates = [
    resolve(fileURLToPath(new URL("./tools/workflow-tool-executors.ts", import.meta.url))),
  ];
  const distCandidates = [
    resolve(fileURLToPath(new URL("../../../../dist/resources/extensions/gsd/tools/workflow-tool-executors.js", import.meta.url))),
    resolve(fileURLToPath(new URL("./tools/workflow-tool-executors.js", import.meta.url))),
  ];
  const candidates = hasTsResolveHook(env) ? [...sourceCandidates, ...distCandidates] : [...distCandidates, ...sourceCandidates];

  for (const candidate of candidates) {
    if (existsSync(candidate)) return candidate;
  }

  return null;
}

function getBundledWorkflowWriteGateModulePath(env: NodeJS.ProcessEnv = process.env): string | null {
  const sourceCandidates = [
