): Record<string, string> {
  const mergedEnv = { ...env, ...(explicitEnv ?? {}) };
  const executorModulePath = getBundledWorkflowExecutorModulePath(mergedEnv);
  const writeGateModulePath = getBundledWorkflowWriteGateModulePath(mergedEnv);

  return {
    ...(explicitEnv ?? {}),
    ...(gsdCliPath ? { GSD_CLI_PATH: gsdCliPath } : {}),
    ...(executorModulePath ? { GSD_WORKFLOW_EXECUTORS_MODULE: executorModulePath } : {}),
