+
+const OTHER_OPTION_LABEL = "None of the above";
+
+function formatAskUserQuestionsResult(result: RoundResult): string {
+  const answers: Record<string, { answers: string[] }> = {};
+  for (const [id, answer] of Object.entries(result.answers)) {
+    const list = Array.isArray(answer.selected) ? [...answer.selected] : [answer.selected];
+    if (answer.notes) {
+      list.push(`user_note: ${answer.notes}`);
+    }
+    answers[id] = { answers: list };
+  }
+  return JSON.stringify({ answers });
+}
+
+function errorAskUserQuestionsResult(message: string, questions: Question[] = []): { content: { type: "text"; text: string }[]; details: unknown } {
+  return {
+    content: [{ type: "text", text: message }],
+    details: { questions, response: null, cancelled: true },
+  };
+}
+
+function buildQuestionSchemaProperty(question: Question): ElicitFormSchemaProperty {
+  const optionLabels = question.options.map((option) => option.label);
+  if (question.allowMultiple) {
+    return {
+      type: "array",
+      title: question.header,
+      description: question.question,
+      minItems: 1,
+      maxItems: optionLabels.length,
+      items: { type: "string", enum: optionLabels },
+      default: optionLabels[0] ? [optionLabels[0]] : undefined,
+    };
+  }
+
+  const labels = [...optionLabels, OTHER_OPTION_LABEL];
+  return {
+    type: "string",
+    title: question.header,
+    description: question.question,
+    enum: labels,
+    enumNames: labels,
+    default: optionLabels[0],
+  };
+}
+
+function buildAskUserQuestionsSchema(questions: Question[]) {
+  const properties: Record<string, ElicitFormSchemaProperty> = {};
+  for (const question of questions) {
+    properties[question.id] = buildQuestionSchemaProperty(question);
+  }
+  return {
+    type: "object" as const,
+    properties,
+    required: questions.map((question) => question.id),
+  };
